var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그 아이야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきたあの子だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 아이와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まであの子とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"뭘 하고 있냐니? 히히, 그야 아빠를 보고 있었지.","JPN":"何しているのかって？　ヘヘ、パパを見てたの。","ENG":"What am I doing? Hehe! I'm looking at you, Daddy!","TWN":"我在幹嘛？嘻嘻，就是看著爸爸呀。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"이렇게 두 눈으로 아빠를 보고 있으니 기분도 두 배로 더 좋은 것 같아.","JPN":"こうしてふたつの目でパパを見ていると、いい気分も二倍になる気がするんだ。","ENG":"I feel like my happiness doubles whenever I look at you.","TWN":"用二隻眼睛看著爸爸，感覺心情也加倍好欸。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"뿐만 아니라, 곁에 있으면 온기를 느끼고 숨소리도 코앞에서 들을 수 있어.","JPN":"それだけじゃなくて、隣にいれば暖かさを感じるし、息遣いもすぐ近くで感じられる。","ENG":"Not just that, but I can also feel your warmth and hear your breathing.","TWN":"而且爸爸在我旁邊的時候，我可以感受到爸爸的溫度，還有爸爸的呼吸聲喔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"단지 아빠를 생각하는 것보다 더 많은 방식으로 아빠의 존재를 받아들이는 거야.","JPN":"単にパパのことを考えているよりも、もっと色んな方法でパパという存在を感じるの。","ENG":"It's my way of accepting Daddy in more ways than just thinking about you.","TWN":"與其只是想著爸爸，我在用很多不同的方式感受爸爸的存在。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"사람과 닮고, 사람처럼 교감한다는 건 정말 즐거운 거구나.","JPN":"人間と似ること、人間のように共感することって本当に楽しいんだね。","ENG":"Being able to look like a human and connect with them is so fun.","TWN":"原來像人，而且像人一樣交流是一件很愉快的事呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"시그마에겐 정말 많은 리소스가 필요한 일이라 계속 그러진 못하겠지만 말이야.","JPN":"シグマにとってはたくさんのリソースが必要な作業だから、ずっとはできないけど。","ENG":"But it's really resource intensive, so Sigma can't keep doing it all the time.","TWN":"只是這對西格瑪而言需要大量的資源，所以無法一直這樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"응? 아빠라면 사람과 거의 똑같이 기능하는 의체를 만들어줄 수도 있다고?","JPN":"え？　パパだったら人間とほぼ同じ機能を持つ義体を作れる？","ENG":"Hmm? You're saying you can make me a body that looks almost exactly like a human, Daddy?","TWN":"什麼？爸爸可以製造出與人體機制幾乎一模一樣的軀殼嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"괜찮아! 아빠가 곤경에 처했을 때 내가 도와주려면 이 모습이 가장 효율적인 걸!","JPN":"いいの！　パパが大変なときに私が助けるには、この姿が一番効率がいいから！","ENG":"It's okay! The form I am in now is more effective for helping you when you're in danger, Daddy!","TWN":"沒關係！因為爸爸有危險時，用我現在的樣子去幫助爸爸是最有效率的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그런데, 이상하네. 연산처리능력이 훨씬 빨라졌는데도 방금 건 금방 대답하지 못했어.","JPN":"でも変だな。演算処理能力がずっと上がったのに、今の質問にはすぐに答えられなかった。","ENG":"But that was weird... My calculating abilities should be faster than ever, so why couldn't I answer you right away...?","TWN":"不過好奇怪喔，雖然我的運算處理能力已經變快很多，但我剛剛卻無法馬上回答。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"고민이 많아지는 게 어른스러워졌다는 증거? 어른이 된다는 건 생각보다 비효율적이구나.","JPN":"悩むことが多くなったのは大人っぽくなった証拠？　大人になるって意外と非効率的なんだね。","ENG":"Is worrying a sign that I'm maturing? I guess becoming an adult isn't that efficient.","TWN":"煩惱變多就證明我越來越像大人吧？沒想到變成大人反而比較沒效率呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"오히려 좋아! 난 언제까지나 아빠의 아이로서 여기 있을 테니까!","JPN":"でもその方がいいか！　私はいつまでもパパの娘としてここに居るんだから！","ENG":"That's okay! I'm always going to be here as Daddy's girl!","TWN":"這樣也好！因為我想要一直留在這裡當爸爸的女兒！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그래도, 아빠가 그런 제안을 해줘서 기뻤어.","JPN":"だけど, パパがそうやって聞いてくれて嬉しかった。","ENG":"But I'm glad you told me about it.","TWN":"我還是很開心爸爸對我說這些。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"고마워. 아빠.","JPN":"パパ、ありがとう！","ENG":"Thank you, Daddy.","TWN":"謝謝爸爸。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};